import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"全文查询、过滤、高亮、聚合、自动补全与 Search After","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"search-query-aggregation"},"headers":[],"relativePath":"05-backend-data/notes/cache-messaging-storage/13-search-query-aggregation-autocomplete-pagination.md","filePath":"05-backend-data/notes/cache-messaging-storage/13-search-query-aggregation-autocomplete-pagination.md","lastUpdated":1784382745000}'),l={name:"05-backend-data/notes/cache-messaging-storage/13-search-query-aggregation-autocomplete-pagination.md"};function o(h,e,s,n,d,c){return t(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="全文查询、过滤、高亮、聚合、自动补全与-search-after" tabindex="-1">全文查询、过滤、高亮、聚合、自动补全与 Search After <a class="header-anchor" href="#全文查询、过滤、高亮、聚合、自动补全与-search-after" aria-label="Permalink to &quot;全文查询、过滤、高亮、聚合、自动补全与 Search After&quot;">​</a></h1><p>搜索请求由召回、过滤、评分、排序和分页组成。相关性查询与结构化过滤承担不同职责；深分页必须使用稳定排序、PIT 和 search_after，而不是无界 from/size。</p><h2 id="_1-能力边界与机制图" tabindex="-1">1. 能力边界与机制图 <a class="header-anchor" href="#_1-能力边界与机制图" aria-label="Permalink to &quot;1. 能力边界与机制图&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;事实输入&quot;] --&gt; B[&quot;索引/处理机制&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;查询或派生输出&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;验证与观测&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;失败恢复/重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>查询链路要同时固定 query DSL、权限 filter、索引/alias、PIT 与 sort 值。相关性分数只在同一索引快照和相同请求条件下可比较；聚合、总数和高亮也必须受同一个权限过滤约束。</p><h2 id="_2-query-context" tabindex="-1">2. Query context <a class="header-anchor" href="#_2-query-context" aria-label="Permalink to &quot;2. Query context&quot;">​</a></h2><p>机制：匹配文档并计算 score。</p><p>实际使用：match、multi_match、bool should。</p><p>主要失败：把权限条件放评分分支导致泄露。</p><p>验证方法：用 explain/profile 与命中集合验证。</p><p>取舍：相关性灵活但计算成本高。</p><p>生产实现 Query context 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_3-filter-context" tabindex="-1">3. Filter context <a class="header-anchor" href="#_3-filter-context" aria-label="Permalink to &quot;3. Filter context&quot;">​</a></h2><p>机制：只判断匹配，不计算相关性并可能缓存 bitset。</p><p>实际使用：tenant、状态、时间、权限边界。</p><p>主要失败：把用户输入 query_string 当权限过滤。</p><p>验证方法：对每个主体做资源级测试。</p><p>取舍：精确快速但不负责排序质量。</p><p>生产实现 Filter context 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_4-bm25" tabindex="-1">4. BM25 <a class="header-anchor" href="#_4-bm25" aria-label="Permalink to &quot;4. BM25&quot;">​</a></h2><p>机制：按词频、逆文档频率和长度归一评分。</p><p>实际使用：文本相关性基线。</p><p>主要失败：把 score 当跨查询可比绝对值。</p><p>验证方法：固定语料比较 ranking evaluation。</p><p>取舍：需要字段 boost 与业务信号校准。</p><p>生产实现 BM25 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_5-bool-query" tabindex="-1">5. Bool query <a class="header-anchor" href="#_5-bool-query" aria-label="Permalink to &quot;5. Bool query&quot;">​</a></h2><p>机制：must/filter/should/must_not 组合条件。</p><p>实际使用：表达结构化召回。</p><p>主要失败：minimum_should_match 默认误解。</p><p>验证方法：用边界用例列真值表。</p><p>取舍：复杂嵌套降低可解释性。</p><p>生产实现 Bool query 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_6-highlight" tabindex="-1">6. Highlight <a class="header-anchor" href="#_6-highlight" aria-label="Permalink to &quot;6. Highlight&quot;">​</a></h2><p>机制：基于匹配 term 和 offset 生成片段。</p><p>实际使用：展示命中上下文。</p><p>主要失败：直接把高亮 HTML 注入 DOM 造成 XSS。</p><p>验证方法：转义原文并只允许受控标签。</p><p>取舍：增加查询/存储 offset 成本。</p><p>生产实现 Highlight 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_7-aggregation" tabindex="-1">7. Aggregation <a class="header-anchor" href="#_7-aggregation" aria-label="Permalink to &quot;7. Aggregation&quot;">​</a></h2><p>机制：在匹配文档上做 bucket/metric/pipeline。</p><p>实际使用：分类面板、统计分布。</p><p>主要失败：高基数 terms size 无界。</p><p>验证方法：观察 bucket 数、内存、误差/其他桶。</p><p>取舍：实时聚合便利但可能压集群。</p><p>生产实现 Aggregation 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_8-autocomplete" tabindex="-1">8. Autocomplete <a class="header-anchor" href="#_8-autocomplete" aria-label="Permalink to &quot;8. Autocomplete&quot;">​</a></h2><p>机制：edge n-gram、completion、search-as-you-type 等候选策略。</p><p>实际使用：前缀建议与拼写体验。</p><p>主要失败：任意 n-gram 导致索引爆炸。</p><p>验证方法：测索引大小、候选精度和输入延迟。</p><p>取舍：预计算快但更新和个性化复杂。</p><p>生产实现 Autocomplete 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_9-from-size" tabindex="-1">9. from/size <a class="header-anchor" href="#_9-from-size" aria-label="Permalink to &quot;9. from/size&quot;">​</a></h2><p>机制：跳过前面 hits 后取页面。</p><p>实际使用：浅分页和后台小数据。</p><p>主要失败：深页每 shard 维护大量候选。</p><p>验证方法：限制 max window 并压测。</p><p>取舍：支持页码但成本随深度上升。</p><p>生产实现 from/size 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_10-search-after" tabindex="-1">10. search_after <a class="header-anchor" href="#_10-search-after" aria-label="Permalink to &quot;10. search_after&quot;">​</a></h2><p>机制：以上一页完整 sort values 作为下一页边界。</p><p>实际使用：稳定向后遍历。</p><p>主要失败：sort 不唯一导致重复/遗漏。</p><p>验证方法：加入唯一 tie-breaker 并检测重复。</p><p>取舍：不能随意跳页，状态需客户端保存。</p><p>生产实现 search_after 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_11-pit" tabindex="-1">11. PIT <a class="header-anchor" href="#_11-pit" aria-label="Permalink to &quot;11. PIT&quot;">​</a></h2><p>机制：固定索引读取视图避免 refresh 改变分页集合。</p><p>实际使用：长列表与导出的一致分页。</p><p>主要失败：忘记关闭/keep_alive 过长占资源。</p><p>验证方法：监控 PIT context、过期恢复。</p><p>取舍：提高一致性但不是数据库事务快照。</p><p>生产实现 PIT 时必须把输入类型、处理上限、输出状态和失败类别写入接口契约；调用方不能根据一次成功响应推导未承诺的持久性、一致性或权限语义。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要收益</th><th>关键边界</th></tr></thead><tbody><tr><td>match</td><td>分析后全文</td><td>计算score</td></tr><tr><td>term</td><td>精确term</td><td>不分析输入</td></tr><tr><td>filter</td><td>结构约束</td><td>无score</td></tr><tr><td>from/size</td><td>页码简单</td><td>深分页昂贵</td></tr><tr><td>PIT+search_after</td><td>稳定游标</td><td>不能随机跳页</td></tr></tbody></table><h2 id="_13-完整案例-商品搜索页" tabindex="-1">13. 完整案例：商品搜索页 <a class="header-anchor" href="#_13-完整案例-商品搜索页" aria-label="Permalink to &quot;13. 完整案例：商品搜索页&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>关键词、品牌、价格区间、tenant权限；显示高亮和品牌聚合；p95 150ms。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>tenant/权限放 filter，关键词用 multi_match 并控制字段boost。</li><li>聚合只在允许字段，terms size 有上限。</li><li>高亮转义原文并限制片段数/长度。</li><li>查询模板白名单，不开放任意脚本/query_string。</li><li>用真实查询集做ranking evaluation和负载测试。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>结果、facet和高亮在权限范围内，延迟有界。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>无权商品不进入hits或聚合计数；高亮不执行HTML；慢查询profile可定位。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>先搜索全局再应用层过滤会泄漏聚合和总数；修正为权限filter进入搜索请求。</p><h3 id="完成判断" tabindex="-1">完成判断 <a class="header-anchor" href="#完成判断" aria-label="Permalink to &quot;完成判断&quot;">​</a></h3><p>商品搜索页的验收以整份响应为单位：golden query 的排序达到约定质量，权限外商品不进入 hits、total 或 facet，高亮经安全渲染，并且慢查询能由 profile 定位到具体 clause 与 shard。</p><h2 id="_14-完整案例-千万结果导出" tabindex="-1">14. 完整案例：千万结果导出 <a class="header-anchor" href="#_14-完整案例-千万结果导出" aria-label="Permalink to &quot;14. 完整案例：千万结果导出&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>按 created_at,id 排序导出，索引持续写入，不能重复遗漏。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>创建PIT并设置有界keep_alive。</li><li>sort使用created_at asc与唯一_id asc。</li><li>每页把最后hit sort数组作为search_after。</li><li>每页续PIT keep_alive并记录导出checkpoint。</li><li>结束/失败关闭PIT，超时则从业务水位重新开始。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>同一PIT内稳定遍历，导出可检查重复ID。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>并发写入时导出集合稳定；一百万条ID无重复；PIT资源回收。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>只按created_at会在同毫秒记录处重复/遗漏；加入唯一tie-breaker。</p><h3 id="完成判断-1" tabindex="-1">完成判断 <a class="header-anchor" href="#完成判断-1" aria-label="Permalink to &quot;完成判断&quot;">​</a></h3><p>导出验收要求在固定 PIT 内遍历全部预期 ID，<code>created_at + _id</code> sort 值严格前进，重复与遗漏均为零；中断恢复要么继续有效 checkpoint，要么从新的业务水位完整重启，并确认 PIT 已释放。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入点</th><th>应观察的系统行为</th><th>不允许的结果</th></tr></thead><tbody><tr><td>输入中加入未知字段/极端长度</td><td>search_p95 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>暂停一个处理节点</td><td>query_cache_hit 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>让下游返回429或503</td><td>fetch_p95 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>制造重复与乱序版本</td><td>aggregation_buckets 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>使磁盘达到高水位</td><td>highlight_bytes 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>让请求在提交后断线</td><td>zero_result_rate 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>撤销一个租户权限</td><td>autocomplete_precision 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr><tr><td>使后台任务积压超过SLO</td><td>deep_page_reject 出现可解释变化并触发受控降级</td><td>静默丢数据、跨权限返回或无限重试</td></tr></tbody></table><h2 id="_16-调试路径与观测信号" tabindex="-1">16. 调试路径与观测信号 <a class="header-anchor" href="#_16-调试路径与观测信号" aria-label="Permalink to &quot;16. 调试路径与观测信号&quot;">​</a></h2><ol><li><code>search_p95</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>query_cache_hit</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>fetch_p95</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>aggregation_buckets</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>highlight_bytes</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>zero_result_rate</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>autocomplete_precision</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>deep_page_reject</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>pit_contexts</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li><li><code>partial_search_results</code>：定义采样点、单位、维度和告警窗口；只使用低基数标签，具体资源 ID 进入受控日志或 trace。</li></ol><p>搜索变慢时先保存完整 DSL、索引、routing、PIT ID 和 shard failure，再比较 query/fetch 两阶段耗时与 profile tree。排序异常检查 BM25 输入和 sort tie-breaker；facet 泄漏检查 filter 是否在搜索执行层，而不是只看应用返回的 hits。</p><h2 id="_17-性能、安全与运维边界" tabindex="-1">17. 性能、安全与运维边界 <a class="header-anchor" href="#_17-性能、安全与运维边界" aria-label="Permalink to &quot;17. 性能、安全与运维边界&quot;">​</a></h2><ol><li>所有用户输入有长度、结构、复杂度和超时上限；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>租户与权限条件来自认证主体，不信任请求正文；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>重试有总预算、退避、抖动和幂等保护；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>派生数据能从事实源按明确水位重建；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>敏感正文不进入普通日志、指标标签或公开快照；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>容量按峰值写入、查询、恢复和副本同时估算；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>发布采用版本化结构、canary、对账和回退窗口；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>删除覆盖索引、缓存、快照与下游派生系统；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>依赖不可用时核心正确性不由降级路径破坏；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li><li>运行手册包含暂停、恢复、验证和人工升级条件；对 全文查询、过滤、高亮、聚合、自动补全与 Search After 的实现要给出责任人和可执行验证。</li></ol><h2 id="_18-综合练习与验收" tabindex="-1">18. 综合练习与验收 <a class="header-anchor" href="#_18-综合练习与验收" aria-label="Permalink to &quot;18. 综合练习与验收&quot;">​</a></h2><p>为“商品搜索页”实现最小生产链路，并把“千万结果导出”作为不同约束下的对照。提交配置、请求/响应、数据样例、故障脚本和观测面板。</p><ul><li>[ ] 验收 1：Query context 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 2：Filter context 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 3：BM25 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 4：Bool query 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 5：Highlight 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 6：Aggregation 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 7：Autocomplete 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 验收 8：from/size 的机制、使用、失败与验证均能用真实输入复现。</li><li>[ ] 商品查询集同时验证 hits、total、aggregation、highlight 与权限过滤，不能只检查首条结果。</li><li>[ ] Autocomplete 记录 prefix 长度分布、precision、索引大小和请求频率，并对空串和超长前缀限流。</li><li>[ ] Search After 导出用稳定唯一排序键，验证 PIT 过期、checkpoint 失效和资源回收路径。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://docs.opensearch.org/latest/api-reference/search-apis/search/" target="_blank" rel="noreferrer">OpenSearch Search API</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/search-plugins/searching-data/paginate/" target="_blank" rel="noreferrer">OpenSearch Paginate results</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/aggregations/" target="_blank" rel="noreferrer">OpenSearch Aggregations</a>（访问日期：2026-07-17）</li><li><a href="https://www.elastic.co/docs/reference/elasticsearch/rest-apis/search-apis" target="_blank" rel="noreferrer">Elasticsearch Search APIs</a>（访问日期：2026-07-17）</li><li><a href="https://docs.opensearch.org/latest/version-history/" target="_blank" rel="noreferrer">OpenSearch 3.7 version history</a>（访问日期：2026-07-17）</li></ul>`,115)])])}const g=a(l,[["render",o]]);export{u as __pageData,g as default};
